GameReward = {}

function GameReward:onPlayerGetReward(player, reward)
    if not reward then
        return
    end
    if reward.RewardType == Define.RewardType.Item then
        local armor = ArmorConfig:getArmorValueById(reward.RewardId)
        local maxMeta = 0
        if armor ~= nil and armor.multiple > 0 then
            maxMeta = armor.ArmorValue * armor.multiple
        end
        player:addItem(reward.RewardId, reward.Count, 0, false, maxMeta)
    end
    if reward.RewardType == Define.RewardType.VIP then
        GameReward:onPlayerRewardVip(player, reward.RewardId, reward.Time)
    end
    return reward.Id
end

function GameReward:onPlayerRewardVip(player, level, time)
    if time <= 0 then
        return
    end
    player.vip_data.level = math.max(player.vip_data.level, level)
    local vipTime = player.vip_data.time
    if vipTime < os.time() then
        vipTime = os.time()
    end
    vipTime = vipTime + time
    player.vip_data.time = vipTime
    player:syncVipInfo()
    player.vip_box = 0
    GameStore:syncSupplyData(player)
end

return GameReward